// Vercel serverless route: GET /api/emba
// Passcode-gated access to a personal resource (EMBA program calendar) that
// contains PII (flight confirmation #, airline loyalty #, TSA KTN). The HTML
// is embedded here (base64) rather than served as a static file under
// /resources/ so there is no unauthenticated static route to the raw content.
//
// Passcode lives in the Vercel project's EMBA_PASSCODE env var — never in git.

const CONTENT_B64 = "";

function lockedPage(message) {
  return `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>Locked</title>
<meta name="robots" content="noindex,nofollow">
<style>
  body{font-family:-apple-system,Inter,sans-serif;background:#f7f8fa;color:#101828;
       display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;}
  .box{background:#fff;border:1px solid #e2e5eb;border-radius:8px;padding:32px 36px;
       max-width:360px;box-shadow:0 1px 3px rgba(0,0,0,.06);}
  h1{font-size:16px;margin:0 0 6px;}
  p{font-size:13px;color:#475467;margin:0 0 16px;}
  input{width:100%;padding:9px 11px;border:1px solid #c7cbd4;border-radius:4px;font-size:13px;
        box-sizing:border-box;margin-bottom:10px;}
  button{width:100%;padding:9px;border:none;border-radius:4px;background:#16324f;color:#fff;
         font-size:13px;font-weight:600;cursor:pointer;}
  .err{color:#b3261e;font-size:12px;margin:0 0 10px;}
</style></head>
<body>
  <div class="box">
    <h1>This resource is private</h1>
    <p>Enter the passcode to view.</p>
    ${message ? `<div class="err">${message}</div>` : ''}
    <form method="GET" action="/api/emba">
      <input type="password" name="key" placeholder="Passcode" autofocus required>
      <button type="submit">View</button>
    </form>
  </div>
</body></html>`;
}

module.exports = (req, res) => {
  const expected = process.env.EMBA_PASSCODE;
  const provided = (req.query && req.query.key) || '';

  if (!expected) {
    res.statusCode = 500;
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.end(lockedPage('Server not configured (missing EMBA_PASSCODE).'));
    return;
  }

  if (provided !== expected) {
    res.statusCode = provided ? 401 : 200;
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.setHeader('X-Robots-Tag', 'noindex, nofollow');
    res.end(lockedPage(provided ? 'Incorrect passcode.' : ''));
    return;
  }

  const html = Buffer.from(CONTENT_B64, 'base64').toString('utf-8');
  res.statusCode = 200;
  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.setHeader('X-Robots-Tag', 'noindex, nofollow');
  res.setHeader('Cache-Control', 'private, no-store');
  res.end(html);
};
